// ============================================================================
// CSV Parser Library
// ============================================================================

/** Configuration options for the CSV parser */
export interface CSVOptions {
  /** Field delimiter character (default: ',') */
  delimiter?: string;
  /** Quote character for wrapping fields (default: '"') */
  quote?: string;
  /** Line separator (default: auto-detect \r\n, \r, or \n) */
  lineSeparator?: string;
  /** Whether to perform automatic type coercion (default: true) */
  typeCoercion?: boolean;
}

/** Represents a parsing error on a specific row */
export interface CSVError {
  row: number;
  message: string;
}

/** A single parsed row as a record of header -> value */
export type CSVRow = Record<string, unknown>;

/** The result object returned by parseCSV */
export interface CSVResult {
  /** Parsed data rows as an array of objects keyed by header names */
  rows: CSVRow[];
  /** The header column names */
  headers: string[];
  /** Any errors encountered during parsing */
  errors: CSVError[];
  /** Filter rows by a predicate function */
  filter(predicate: (row: CSVRow) => boolean): CSVRow[];
  /** Sum all numeric values in a given column */
  sum(column: string): number;
  /** Average all numeric values in a given column */
  average(column: string): number;
  /** Count total rows */
  count(): number;
  /** Group rows by the values in a given column */
  groupBy(column: string): Map<unknown, CSVRow[]>;
}

// ============================================================================
// Internal: Field-level parser using a state machine
// ============================================================================

const enum FieldState {
  Start,
  UnquotedField,
  QuotedField,
  QuoteInQuotedField,
}

/**
 * Parse a single CSV line into an array of raw string fields.
 * Handles quoted fields, escaped quotes, and embedded delimiters.
 *
 * Returns `null` if the line is malformed (e.g. unmatched quotes).
 */
function parseFields(
  line: string,
  delimiter: string,
  quote: string
): string[] | null {
  const fields: string[] = [];
  let state: FieldState = FieldState.Start;
  let current = "";
  let i = 0;

  while (i <= line.length) {
    const ch = i < line.length ? line[i] : undefined; // undefined = EOL

    switch (state) {
      case FieldState.Start:
        if (ch === undefined) {
          // EOL at field start → empty trailing field
          fields.push("");
          i++;
        } else if (ch === quote) {
          state = FieldState.QuotedField;
          current = "";
          i++;
        } else if (ch === delimiter) {
          fields.push("");
          i++;
          // stay in Start for next field
        } else {
          state = FieldState.UnquotedField;
          current = ch;
          i++;
        }
        break;

      case FieldState.UnquotedField:
        if (ch === undefined || ch === delimiter) {
          fields.push(current);
          current = "";
          state = FieldState.Start;
          i++;
        } else {
          current += ch;
          i++;
        }
        break;

      case FieldState.QuotedField:
        if (ch === undefined) {
          // EOL inside a quoted field → malformed
          return null;
        } else if (ch === quote) {
          state = FieldState.QuoteInQuotedField;
          i++;
        } else {
          current += ch;
          i++;
        }
        break;

      case FieldState.QuoteInQuotedField:
        if (ch === quote) {
          // Escaped quote (two quotes → one literal)
          current += quote;
          state = FieldState.QuotedField;
          i++;
        } else if (ch === delimiter || ch === undefined) {
          // End of quoted field
          fields.push(current);
          current = "";
          state = FieldState.Start;
          i++;
        } else {
          // Character after closing quote that isn't delimiter or EOL → malformed
          return null;
        }
        break;
    }
  }

  return fields;
}

// ============================================================================
// Internal: Type coercion
// ============================================================================

function coerceValue(raw: string): unknown {
  // Null / empty
  if (raw === "" || raw === "null" || raw === "NULL") {
    return null;
  }

  // Boolean (case-insensitive)
  const lower = raw.toLowerCase();
  if (lower === "true") return true;
  if (lower === "false") return false;

  // Number – must be the *entire* string, no extra whitespace trickery
  // We reject strings like "" (already handled), "  ", "Infinity", "NaN"
  if (/^-?(\d+\.?\d*|\.\d+)([eE][+-]?\d+)?$/.test(raw)) {
    const num = Number(raw);
    if (Number.isFinite(num)) return num;
  }

  return raw;
}

// ============================================================================
// Internal: Line splitting with auto-detection
// ============================================================================

function splitLines(input: string, lineSeparator?: string): string[] {
  if (lineSeparator !== undefined) {
    return input.split(lineSeparator);
  }

  // Auto-detect: try \r\n first, then \r, then \n
  if (input.includes("\r\n")) {
    return input.split("\r\n");
  } else if (input.includes("\r")) {
    return input.split("\r");
  }
  return input.split("\n");
}

// ============================================================================
// Public API
// ============================================================================

/**
 * Parse a CSV string into a structured result with rows, headers, errors,
 * and utility methods for filtering and aggregation.
 */
export function parseCSV(input: string, options?: CSVOptions): CSVResult {
  const delimiter = options?.delimiter ?? ",";
  const quote = options?.quote ?? '"';
  const lineSeparator = options?.lineSeparator;
  const typeCoercion = options?.typeCoercion ?? true;

  const errors: CSVError[] = [];
  const rows: CSVRow[] = [];

  // ---- Handle empty / whitespace-only input --------------------------------
  if (input.trim() === "") {
    return buildResult([], [], errors);
  }

  // ---- Split into lines ----------------------------------------------------
  const lines = splitLines(input, lineSeparator);

  // Remove trailing empty line that results from a final newline
  if (lines.length > 0 && lines[lines.length - 1].trim() === "") {
    lines.pop();
  }

  if (lines.length === 0) {
    return buildResult([], [], errors);
  }

  // ---- Parse headers -------------------------------------------------------
  const headerFields = parseFields(lines[0], delimiter, quote);
  if (headerFields === null) {
    errors.push({ row: 1, message: "Malformed header row" });
    return buildResult([], [], errors);
  }
  const headers = headerFields.map((h) => h.trim());

  // ---- Parse data rows -----------------------------------------------------
  for (let i = 1; i < lines.length; i++) {
    const line = lines[i];

    // Skip completely empty lines in the middle
    if (line.trim() === "") {
      continue;
    }

    const rowNum = i + 1; // 1-based row numbering
    const fields = parseFields(line, delimiter, quote);

    if (fields === null) {
      errors.push({
        row: rowNum,
        message: "Malformed row: unmatched or misplaced quote character",
      });
      continue;
    }

    if (fields.length !== headers.length) {
      errors.push({
        row: rowNum,
        message: `Column count mismatch: expected ${headers.length} but got ${fields.length}`,
      });
      // Still attempt to build the row with available data
    }

    const rowObj: CSVRow = {};
    for (let j = 0; j < headers.length; j++) {
      const raw = j < fields.length ? fields[j] : "";
      rowObj[headers[j]] = typeCoercion ? coerceValue(raw) : raw;
    }
    rows.push(rowObj);
  }

  return buildResult(headers, rows, errors);
}

// ============================================================================
// Result builder – attaches utility methods
// ============================================================================

function buildResult(
  headers: string[],
  rows: CSVRow[],
  errors: CSVError[]
): CSVResult {
  return {
    headers,
    rows,
    errors,

    filter(predicate: (row: CSVRow) => boolean): CSVRow[] {
      return rows.filter(predicate);
    },

    sum(column: string): number {
      let total = 0;
      for (const row of rows) {
        const val = row[column];
        if (typeof val === "number") {
          total += val;
        }
      }
      return total;
    },

    average(column: string): number {
      let total = 0;
      let count = 0;
      for (const row of rows) {
        const val = row[column];
        if (typeof val === "number") {
          total += val;
          count++;
        }
      }
      return count === 0 ? 0 : total / count;
    },

    count(): number {
      return rows.length;
    },

    groupBy(column: string): Map<unknown, CSVRow[]> {
      const map = new Map<unknown, CSVRow[]>();
      for (const row of rows) {
        const key = row[column];
        const existing = map.get(key);
        if (existing) {
          existing.push(row);
        } else {
          map.set(key, [row]);
        }
      }
      return map;
    },
  };
}

// ============================================================================
// CSV Parser – Comprehensive Test Suite
// ============================================================================
// No test framework – plain assertions. Throws on first failure.

import { parseCSV, CSVResult, CSVRow, CSVOptions, CSVError } from "./csv-parser";

// ---- Helpers ---------------------------------------------------------------

let passed = 0;
let failed = 0;
const failures: string[] = [];

function assert(condition: boolean, message: string): void {
  if (!condition) {
    failed++;
    failures.push(message);
    console.error(`  ✗ FAIL: ${message}`);
  } else {
    passed++;
    console.log(`  ✓ ${message}`);
  }
}

function assertEqual<T>(actual: T, expected: T, message: string): void {
  const a = JSON.stringify(actual);
  const e = JSON.stringify(expected);
  if (a !== e) {
    failed++;
    const detail = `${message}\n      expected: ${e}\n      actual:   ${a}`;
    failures.push(detail);
    console.error(`  ✗ FAIL: ${detail}`);
  } else {
    passed++;
    console.log(`  ✓ ${message}`);
  }
}

function assertClose(actual: number, expected: number, epsilon: number, message: string): void {
  if (Math.abs(actual - expected) > epsilon) {
    failed++;
    const detail = `${message} (expected ~${expected}, got ${actual})`;
    failures.push(detail);
    console.error(`  ✗ FAIL: ${detail}`);
  } else {
    passed++;
    console.log(`  ✓ ${message}`);
  }
}

function section(title: string): void {
  console.log(`\n═══ ${title} ═══`);
}

// ============================================================================
// 1. BASIC PARSING
// ============================================================================
section("Basic Parsing");

{
  const csv = `name,age,city
Alice,30,New York
Bob,25,London`;
  const result = parseCSV(csv);

  assertEqual(result.headers, ["name", "age", "city"], "headers parsed correctly");
  assertEqual(result.rows.length, 2, "two data rows parsed");
  assertEqual(result.rows[0]["name"], "Alice", "first row name");
  assertEqual(result.rows[0]["age"], 30, "first row age (number coerced)");
  assertEqual(result.rows[0]["city"], "New York", "first row city");
  assertEqual(result.rows[1]["name"], "Bob", "second row name");
  assertEqual(result.rows[1]["age"], 25, "second row age");
  assertEqual(result.rows[1]["city"], "London", "second row city");
  assertEqual(result.errors.length, 0, "no errors on valid input");
}

{
  const csv = `name,age,city
Alice,30,New York
Bob,25,London
`;
  const result = parseCSV(csv);

  assertEqual(result.rows.length, 2, "trailing newline doesn't create extra row");
  assertEqual(result.errors.length, 0, "no errors with trailing newline");
}

{
  const csv = `id,value
1,hello
2,world
3,foo`;
  const result = parseCSV(csv);

  assertEqual(result.rows.length, 3, "three rows parsed");
  assertEqual(result.rows[2]["id"], 3, "third row id");
  assertEqual(result.rows[2]["value"], "foo", "third row value");
}

// ============================================================================
// 2. QUOTED FIELDS
// ============================================================================
section("Quoted Fields");

{
  const csv = `name,description,price
Widget,"A cool, useful gadget",9.99
Gizmo,"Another product",4.50`;
  const result = parseCSV(csv);

  assertEqual(result.rows[0]["description"], "A cool, useful gadget", "quoted field with comma preserved");
  assertEqual(result.rows[0]["price"], 9.99, "price after quoted field parsed");
  assertEqual(result.rows[1]["description"], "Another product", "simple quoted field");
  assertEqual(result.errors.length, 0, "no errors with quoted fields");
}

{
  const csv = `a,b
"hello","world"
"foo","bar"`;
  const result = parseCSV(csv);

  assertEqual(result.rows[0]["a"], "hello", "all-quoted fields work (a)");
  assertEqual(result.rows[0]["b"], "world", "all-quoted fields work (b)");
}

{
  const csv = `col
"field with, multiple, commas"`;
  const result = parseCSV(csv);

  assertEqual(result.rows[0]["col"], "field with, multiple, commas", "multiple commas inside quotes");
}

// ============================================================================
// 3. ESCAPED QUOTES
// ============================================================================
section("Escaped Quotes");

{
  const csv = `name,quote
Alice,"She said ""hello"" loudly"
Bob,"He replied ""goodbye"""`;
  const result = parseCSV(csv);

  assertEqual(result.rows[0]["quote"], 'She said "hello" loudly', "escaped quotes in middle of field");
  assertEqual(result.rows[1]["quote"], 'He replied "goodbye"', "escaped quotes at end of field");
  assertEqual(result.errors.length, 0, "no errors with escaped quotes");
}

{
  const csv = `col
""""""`; // six quotes → field is ""
  const result = parseCSV(csv);

  assertEqual(result.rows[0]["col"], '""', "multiple escaped quotes (6 quotes → 2 literal)");
}

{
  const csv = `col
""`;  // two quotes → empty quoted field → null (empty string coerced)
  const result = parseCSV(csv);

  assertEqual(result.rows[0]["col"], null, "empty quoted field → null with coercion");
}

// ============================================================================
// 4. CUSTOM DELIMITERS
// ============================================================================
section("Custom Delimiters");

{
  const csv = `name\tage\tcity
Alice\t30\tNew York
Bob\t25\tLondon`;
  const result = parseCSV(csv, { delimiter: "\t" });

  assertEqual(result.headers, ["name", "age", "city"], "tab-delimited headers");
  assertEqual(result.rows[0]["name"], "Alice", "tab-delimited first field");
  assertEqual(result.rows[0]["age"], 30, "tab-delimited second field");
  assertEqual(result.rows[0]["city"], "New York", "tab-delimited third field");
}

{
  const csv = `name;age;city
Alice;30;Paris
Bob;25;Lyon`;
  const result = parseCSV(csv, { delimiter: ";" });

  assertEqual(result.headers, ["name", "age", "city"], "semicolon-delimited headers");
  assertEqual(result.rows[0]["city"], "Paris", "semicolon-delimited city");
  assertEqual(result.rows[1]["city"], "Lyon", "semicolon second row");
}

{
  const csv = `name|desc|val
Alice|'has, commas'|10
Bob|'normal'|20`;
  const result = parseCSV(csv, { delimiter: "|", quote: "'" });

  assertEqual(result.rows[0]["desc"], "has, commas", "custom quote char with commas inside");
  assertEqual(result.rows[1]["desc"], "normal", "custom quote char simple field");
}

{
  const csv = `name,age,city|Alice,30,NYC|Bob,25,LA`;
  const result = parseCSV(csv, { lineSeparator: "|" });

  assertEqual(result.headers, ["name", "age", "city"], "custom line separator headers");
  assertEqual(result.rows.length, 2, "custom line separator row count");
  assertEqual(result.rows[0]["city"], "NYC", "custom line separator first row");
  assertEqual(result.rows[1]["city"], "LA", "custom line separator second row");
}

// ============================================================================
// 5. TYPE COERCION
// ============================================================================
section("Type Coercion");

{
  const csv = `int,float,neg,negfloat,sci
42,3.14,-7,-2.5,1e10`;
  const result = parseCSV(csv);

  assert(result.rows[0]["int"] === 42, "integer coercion");
  assert(result.rows[0]["float"] === 3.14, "float coercion");
  assert(result.rows[0]["neg"] === -7, "negative integer coercion");
  assert(result.rows[0]["negfloat"] === -2.5, "negative float coercion");
  assert(result.rows[0]["sci"] === 1e10, "scientific notation coercion");
}

{
  const csv = `a,b,c,d
true,false,TRUE,False`;
  const result = parseCSV(csv);

  assert(result.rows[0]["a"] === true, "boolean true (lowercase)");
  assert(result.rows[0]["b"] === false, "boolean false (lowercase)");
  assert(result.rows[0]["c"] === true, "boolean TRUE (uppercase)");
  assert(result.rows[0]["d"] === false, "boolean False (mixed case)");
}

{
  const csv = `a,b,c
null,NULL,`;
  const result = parseCSV(csv);

  assert(result.rows[0]["a"] === null, "null string → null");
  assert(result.rows[0]["b"] === null, "NULL string → null");
  assert(result.rows[0]["c"] === null, "empty string → null");
}

{
  const csv = `a,b,c
hello,with spaces,special-chars_123`;
  const result = parseCSV(csv);

  assert(result.rows[0]["a"] === "hello", "plain string stays string");
  assert(result.rows[0]["b"] === "with spaces", "string with spaces stays string");
  assert(result.rows[0]["c"] === "special-chars_123", "mixed alphanumeric stays string");
}

{
  const csv = `val
.5`;
  const result = parseCSV(csv);

  assert(result.rows[0]["val"] === 0.5, "leading dot float (.5 → 0.5)");
}

{
  const csv = `val
1e3`;
  const result = parseCSV(csv);

  assert(result.rows[0]["val"] === 1000, "scientific notation 1e3");
}

{
  // Type coercion disabled
  const csv = `a,b,c
42,true,null`;
  const result = parseCSV(csv, { typeCoercion: false });

  assert(result.rows[0]["a"] === "42", "no coercion: number stays string");
  assert(result.rows[0]["b"] === "true", "no coercion: boolean stays string");
  assert(result.rows[0]["c"] === "null", "no coercion: null stays string");
}

{
  const csv = `val
0`;
  const result = parseCSV(csv);

  assert(result.rows[0]["val"] === 0, "zero coerced to number 0 (not falsy null)");
}

{
  const csv = `val
-0.75`;
  const result = parseCSV(csv);

  assert(result.rows[0]["val"] === -0.75, "negative float -0.75");
}

{
  const csv = `val
3.`;
  // "3." – ends with dot. Our regex requires digits after dot or dot before digits.
  // 3. matches -?(\d+\.?\d*) where \d+ = 3, \.? = ., \d* = empty → valid
  const result = parseCSV(csv);
  assert(result.rows[0]["val"] === 3, "trailing dot number (3. → 3)");
}

// ============================================================================
// 6. ERROR HANDLING – MALFORMED ROWS
// ============================================================================
section("Error Handling");

{
  const csv = `name,age,city
Alice,30,New York
Bob,25
Charlie,35,Berlin`;
  const result = parseCSV(csv);

  assert(result.rows.length === 3, "malformed row still produces row object");
  assert(result.errors.length === 1, "one error collected for column mismatch");
  assert(result.errors[0].row === 3, "error on correct row number (1-based)");
  assert(result.errors[0].message.includes("Column count mismatch"), "error message describes mismatch");
}

{
  const csv = `name,age
Alice,30
"unclosed quote,25
Bob,40`;
  const result = parseCSV(csv);

  assert(result.errors.length === 1, "one error for unclosed quote");
  assert(result.errors[0].row === 3, "unclosed quote error on row 3");
  assert(result.errors[0].message.includes("unmatched"), "error mentions unmatched quote");
  // The valid rows should still be parsed
  assert(result.rows.length === 2, "valid rows still parsed despite error");
  assertEqual(result.rows[0]["name"], "Alice", "first valid row present");
  assertEqual(result.rows[1]["name"], "Bob", "row after error still parsed");
}

{
  const csv = `a,b,c
1,2,3,4
5,6,7`;
  const result = parseCSV(csv);

  assert(result.errors.length === 1, "extra column triggers error");
  assert(result.errors[0].row === 2, "error on row with extra columns");
}

{
  const csv = `a,b
"bad"data,2`;
  const result = parseCSV(csv);

  assert(result.errors.length === 1, "text after closing quote triggers error");
  assert(result.errors[0].message.includes("unmatched") || result.errors[0].message.includes("misplaced"), "error describes quote issue");
}

{
  // Multiple errors
  const csv = `a,b
"broken,1
also"broken,2
ok,3`;
  const result = parseCSV(csv);

  assert(result.errors.length === 2, "multiple errors collected");
  assert(result.errors[0].row === 2, "first error row");
  assert(result.errors[1].row === 3, "second error row");
  assert(result.rows.length === 1, "only valid row parsed");
}

// ============================================================================
// 7. FILTER FUNCTIONALITY
// ============================================================================
section("Filter");

{
  const csv = `name,age,active
Alice,30,true
Bob,25,false
Charlie,35,true
Diana,28,false`;
  const result = parseCSV(csv);

  const activeOnly = result.filter((row) => row["active"] === true);
  assertEqual(activeOnly.length, 2, "filter returns correct count");
  assertEqual(activeOnly[0]["name"], "Alice", "filter first match");
  assertEqual(activeOnly[1]["name"], "Charlie", "filter second match");
}

{
  const csv = `name,score
Alice,85
Bob,92
Charlie,78
Diana,95`;
  const result = parseCSV(csv);

  const highScores = result.filter((row) => (row["score"] as number) >= 90);
  assertEqual(highScores.length, 2, "filter by numeric comparison");
  assertEqual(highScores[0]["name"], "Bob", "filter numeric first match");
  assertEqual(highScores[1]["name"], "Diana", "filter numeric second match");
}

{
  const csv = `x
1
2
3`;
  const result = parseCSV(csv);

  const none = result.filter(() => false);
  assertEqual(none.length, 0, "filter returning nothing gives empty array");

  const all = result.filter(() => true);
  assertEqual(all.length, 3, "filter returning everything gives all rows");
}

// ============================================================================
// 8. AGGREGATION METHODS
// ============================================================================
section("Aggregation – count()");

{
  const csv = `a
1
2
3
4
5`;
  const result = parseCSV(csv);

  assertEqual(result.count(), 5, "count returns total rows");
}

{
  const result = parseCSV("");
  assertEqual(result.count(), 0, "count on empty input is 0");
}

// ---- sum() -----------------------------------------------------------------
section("Aggregation – sum()");

{
  const csv = `item,price
A,10
B,20.5
C,30`;
  const result = parseCSV(csv);

  assertClose(result.sum("price"), 60.5, 0.001, "sum of numeric column");
}

{
  const csv = `item,price
A,10
B,n/a
C,30`;
  const result = parseCSV(csv);

  assertEqual(result.sum("price"), 40, "sum skips non-numeric values");
}

{
  const csv = `item,name
A,Alice
B,Bob`;
  const result = parseCSV(csv);

  assertEqual(result.sum("name"), 0, "sum of non-numeric column is 0");
}

{
  const csv = `val
-5
10
-3`;
  const result = parseCSV(csv);

  assertEqual(result.sum("val"), 2, "sum with negative numbers");
}

// ---- average() -------------------------------------------------------------
section("Aggregation – average()");

{
  const csv = `item,score
A,10
B,20
C,30`;
  const result = parseCSV(csv);

  assertClose(result.average("score"), 20, 0.001, "average of numeric column");
}

{
  const csv = `item,score
A,10
B,n/a
C,30`;
  const result = parseCSV(csv);

  assertClose(result.average("score"), 20, 0.001, "average skips non-numeric values");
}

{
  const csv = `item,name
A,Alice
B,Bob`;
  const result = parseCSV(csv);

  assertEqual(result.average("name"), 0, "average of non-numeric column is 0");
}

{
  const result = parseCSV("val\n");
  assertEqual(result.average("val"), 0, "average of empty dataset is 0");
}

// ---- groupBy() -------------------------------------------------------------
section("Aggregation – groupBy()");

{
  const csv = `name,dept,salary
Alice,Engineering,100
Bob,Sales,80
Charlie,Engineering,110
Diana,Sales,90
Eve,Engineering,95`;
  const result = parseCSV(csv);

  const groups = result.groupBy("dept");
  assert(groups instanceof Map, "groupBy returns a Map");
  assertEqual(groups.size, 2, "two groups");

  const eng = groups.get("Engineering")!;
  assertEqual(eng.length, 3, "Engineering has 3 members");
  assertEqual(eng[0]["name"], "Alice", "Engineering first member");

  const sales = groups.get("Sales")!;
  assertEqual(sales.length, 2, "Sales has 2 members");
}

{
  const csv = `name,active
Alice,true
Bob,false
Charlie,true`;
  const result = parseCSV(csv);

  const groups = result.groupBy("active");
  assertEqual(groups.size, 2, "groupBy boolean values");
  assertEqual(groups.get(true)!.length, 2, "true group has 2 rows");
  assertEqual(groups.get(false)!.length, 1, "false group has 1 row");
}

{
  const csv = `name,score
Alice,null
Bob,85
Charlie,null`;
  const result = parseCSV(csv);

  const groups = result.groupBy("score");
  assertEqual(groups.get(null)!.length, 2, "groupBy null values");
  assertEqual(groups.get(85)!.length, 1, "groupBy numeric value");
}

// ============================================================================
// 9. EDGE CASES
// ============================================================================
section("Edge Cases – Empty Input");

{
  const result = parseCSV("");
  assertEqual(result.headers, [], "empty string → no headers");
  assertEqual(result.rows, [], "empty string → no rows");
  assertEqual(result.errors, [], "empty string → no errors");
}

{
  const result = parseCSV("   \n   \n  ");
  assertEqual(result.headers, [], "whitespace-only input → no headers");
  assertEqual(result.rows, [], "whitespace-only input → no rows");
}

section("Edge Cases – Single Column");

{
  const csv = `value
42
hello
true
null`;
  const result = parseCSV(csv);

  assertEqual(result.headers, ["value"], "single column header");
  assertEqual(result.rows.length, 4, "single column four rows");
  assert(result.rows[0]["value"] === 42, "single col: number");
  assert(result.rows[1]["value"] === "hello", "single col: string");
  assert(result.rows[2]["value"] === true, "single col: boolean");
  assert(result.rows[3]["value"] === null, "single col: null");
}

section("Edge Cases – Single Row (headers only)");

{
  const csv = `name,age,city`;
  const result = parseCSV(csv);

  assertEqual(result.headers, ["name", "age", "city"], "headers-only: headers present");
  assertEqual(result.rows.length, 0, "headers-only: no data rows");
  assertEqual(result.count(), 0, "headers-only: count is 0");
}

section("Edge Cases – Single Data Row");

{
  const csv = `name,age
Alice,30`;
  const result = parseCSV(csv);

  assertEqual(result.rows.length, 1, "single data row count");
  assertEqual(result.rows[0]["name"], "Alice", "single data row value");
}

section("Edge Cases – Very Large Fields");

{
  const bigValue = "x".repeat(100_000);
  const csv = `col\n${bigValue}`;
  const result = parseCSV(csv);

  assertEqual(result.rows.length, 1, "very large field: row parsed");
  assertEqual((result.rows[0]["col"] as string).length, 100_000, "very large field: correct length");
  assertEqual(result.errors.length, 0, "very large field: no errors");
}

{
  const bigQuoted = "y".repeat(50_000) + "," + "z".repeat(50_000);
  const csv = `col\n"${bigQuoted}"`;
  const result = parseCSV(csv);

  assertEqual(result.rows.length, 1, "large quoted field with comma: row parsed");
  assertEqual((result.rows[0]["col"] as string).length, 100_001, "large quoted field: correct length including comma");
}

section("Edge Cases – Many Rows");

{
  const lines = ["id,value"];
  for (let i = 0; i < 10_000; i++) {
    lines.push(`${i},val_${i}`);
  }
  const csv = lines.join("\n");
  const result = parseCSV(csv);

  assertEqual(result.count(), 10_000, "10k rows parsed");
  assertEqual(result.rows[0]["id"], 0, "first of 10k rows");
  assertEqual(result.rows[9999]["id"], 9999, "last of 10k rows");
  assertEqual(result.errors.length, 0, "10k rows: no errors");
}

section("Edge Cases – Windows Line Endings (CRLF)");

{
  const csv = "name,age\r\nAlice,30\r\nBob,25\r\n";
  const result = parseCSV(csv);

  assertEqual(result.rows.length, 2, "CRLF: two rows parsed");
  assertEqual(result.rows[0]["name"], "Alice", "CRLF: first row name");
  assertEqual(result.rows[1]["name"], "Bob", "CRLF: second row name");
