section("Edge Cases – Old Mac Line Endings (CR only)");

{
  const csv = "name,age\rAlice,30\rBob,25\r";
  const result = parseCSV(csv);

  assertEqual(result.rows.length, 2, "CR: two rows parsed");
  assertEqual(result.rows[0]["name"], "Alice", "CR: first row name");
}

section("Edge Cases – Whitespace in Headers");

{
