Alice,30,NYC`;
  const result = parseCSV(csv);

  assertEqual(result.headers, ["name", "age", "city"], "headers trimmed of whitespace");
}

section("Edge Cases – Missing Fields Fill With Null");

{
  const csv = `a,b,c
1,2`;
  const result = parseCSV(csv);

