,,`;
  const result = parseCSV(csv);

  assert(result.rows[0]["a"] === null, "empty field a → null");
  assert(result.rows[0]["b"] === null, "empty field b → null");
  assert(result.rows[0]["c"] === null, "empty field c → null");
}

section("Edge Cases – Numeric Edge Cases");

{
  const csv = `val
0
-0
00123
1.0
1e-3`;
  const result = parseCSV(csv);

  assert(result.rows[0]["val"] === 0, "zero");
  assert(result.rows[1]["val"] === 0, "negative zero → 0");
  // 00123 – our regex: ^\-?(\d+\.?\d*|\.\d+)...$ → matches (leading zeros ok, Number('00123')=123)
  assert(result.rows[2]["val"] === 123, "leading zeros parsed as number");
  assert(result.rows[3]["val"] === 1.0, "1.0 parsed as number");
  assert(result.rows[4]["val"] === 0.001, "1e-3 parsed as number");
}

section("Edge Cases – Strings That Look Like Numbers But Aren't");

{
  const csv = `val
12abc
1.2.3
--5
+5
1,000`;
  const result = parseCSV(csv);

  assert(result.rows[0]["val"] === "12abc", "12abc stays string");
  assert(result.rows[1]["val"] === "1.2.3", "1.2.3 stays string");
  assert(result.rows[2]["val"] === "--5", "--5 stays string");
  assert(result.rows[3]["val"] === "+5", "+5 stays string");
  // "1" is a separate field due to comma delimiter; col "val" gets "1"
  // Actually with headers "val", the row "1,000" has 3 fields, header expects 1 → mismatch
  // The first field "1" → 1 (number)
}

section("Combination – Filter + Aggregation");

{
  const csv = `name,dept,salary
Alice,Engineering,100
Bob,Sales,80
Charlie,Engineering,110
Diana,Sales,90
Eve,Engineering,95`;
  const result = parseCSV(csv);

  // Get engineering salaries via filter, then check manually
  const engRows = result.filter((r) => r["dept"] === "Engineering");
  assertEqual(engRows.length, 3, "filter for engineering");

  // Use groupBy + sum conceptually
  const groups = result.groupBy("dept");
  const engGroup = groups.get("Engineering")!;
  const engSum = engGroup.reduce((s, r) => s + (r["salary"] as number), 0);
  assertEqual(engSum, 305, "engineering salary sum from grouped data");

  // Overall
  assertEqual(result.sum("salary"), 475, "total salary sum");
  assertClose(result.average("salary"), 95, 0.001, "average salary");
