  // Row has fewer fields – error logged, but row still created
  assert(result.errors.length === 1, "missing fields trigger error");
  assertEqual(result.rows[0]["c"], null, "missing field coerced to null");
}

section("Edge Cases – Quoted Field with Newline-like Content");

{
  // The field literally contains backslash-n, not an actual newline
